1	type Item = { type: string };
2	type Step = { op: "quote"; items: Item[] };
3	type Customer = { yearsWithMHPCO: number };
4	type Scenario = { customer: Customer; steps: Step[] };
5	type QuoteResult = { premium: number };
6	
7	const PROCESSING_FEE = 5;
8	const FIRST_INSURANCE_RATE = 0.1;
9	
10	const BASE_PREMIUMS: Record<string, number> = {
11	  sword: 100,
12	  amulet: 60,
13	  staff: 80,
14	  potion: 40,
15	};
16	
17	const quoteStep = (step: Step): QuoteResult => {
18	  const itemsBase = step.items.reduce((sum, item) => sum + BASE_PREMIUMS[item.type], 0);
19	  const firstInsurance = itemsBase * FIRST_INSURANCE_RATE;
20	  const premium = Math.ceil(itemsBase + firstInsurance) + PROCESSING_FEE;
21	  return { premium };
22	};
23	
24	export const runScenario = (scenario: Scenario): { results: QuoteResult[] } => {
25	  const results = scenario.steps.map(quoteStep);
26	  return { results };
27	};
